"""
modules/cyber_risk_actuarial.py — ProQuant Capital | Siber Risk & Aktüerya Motoru v11.0
========================================================================================
Kurumların Ransomware ve DDoS siber saldırı risklerini matematiksel olarak fiyatlandıran
ve Siber Sigorta prim hesaplarını çıkaran aktüerya çekirdeği.
Author: ProQuant Capital Cyber-Risk Unit | Version: 11.0.0
"""
class CyberRiskActuarialEngine:
    def calculate_insurance_premium(self, base_rate: float, vulnerabilities: int, employee_training_score: float) -> float:
        """Güvenlik zafiyetine göre prim fiyatlaması."""
        risk_multiplier = 1.0 + (vulnerabilities * 0.1) - (employee_training_score * 0.05)
        return max(base_rate, base_rate * risk_multiplier)

